        const {onClick} = result.current.getSelectedItemProps({
          index: 1,
          selectedItem: items[1],
          onClick: userOnClick,
        })

        onClick({})
      })

      expect(userOnClick).toHaveBeenCalledTimes(1)
      expect(result.current.activeIndex).toBe(-1)
    })

